def simulate(action: str, target_id: str, risk_score: float, depth: int = 2) -> dict:
    score = min(100.0, risk_score + (10 if action.lower() in {"observe","flag","escalate"} else 4))
    outcomes = []
    flags = []
    if action.lower() == "observe":
        outcomes.extend([
