        "subject": normalize_entity(subject),
        "object": normalize_entity(object_),
        "location": normalize_entity(location),
        "payload": payload,
    }, sort_keys=True)
    return hashlib.sha256(blob.encode("utf-8")).hexdigest()[:24]

